           (IF(EXISTS { obo:GO_0120224 rdfs:subClassOf obo:GO_0160108 }, "UNDER GO:0160108 (correct)", "NOT under (WRONG)") AS ?result)
    WHERE {}
  } UNION {
    SELECT ("plant: flower development GO:0009908 (should NOT be under)" AS ?test)
           (IF(EXISTS { obo:GO_0009908 rdfs:subClassOf obo:GO_0160108 }, "UNDER (WRONG)", "NOT under GO:0160108 (correct)") AS ?result)
    WHERE {}
  } UNION {
    SELECT ("plant: root development GO:0048364 (should NOT be under)" AS ?test)
           (IF(EXISTS { obo:GO_0048364 rdfs:subClassOf obo:GO_0160108 }, "UNDER (WRONG)", "NOT under GO:0160108 (correct)") AS ?result)
    WHERE {}
